// src/services/api.js
import axios from 'axios';

const api = axios.create({
    baseURL: 'http://localhost:5005/api',
    headers: {
        'Content-Type': 'application/json',
    },
    timeout: 10000,
});

// Interceptor request - menambahkan token ke setiap request
api.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        console.log('Request URL:', config.url);
        console.log('Token ada?', !!token);

        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }

        // Untuk FormData, jangan set Content-Type (axios akan otomatis set dengan boundary)
        if (config.data instanceof FormData) {
            delete config.headers['Content-Type'];
        }

        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// Interceptor response - menangani error global
api.interceptors.response.use(
    (response) => {
        return response;
    },
    (error) => {
        if (error.response?.status === 401) {
            console.error('Unauthorized! Token mungkin expired atau tidak valid.');
            // Optional: redirect ke login jika token expired
            // if (window.location.pathname !== '/login') {
            //     localStorage.removeItem('token');
            //     localStorage.removeItem('role');
            //     window.location.href = '/login';
            // }
        }
        return Promise.reject(error);
    }
);

export default api;
